// Brand fonts embedded as base64 so the edge function needs no runtime
// fetch or bundler asset-inclusion for TTFs (a fetch(new URL(...ttf)) at
// module scope crashed the deployed function: FUNCTION_INVOCATION_FAILED).
// Decoded once at module init in _fonts.ts's consumer.

export const FRAUNCES_600_B64 =
  "";

export const JAKARTA_700_B64 =
  "";

export const JAKARTA_800_B64 =
  "";

export function fontBytes(b64: string): ArrayBuffer {
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return bytes.buffer;
}
